public int compareTo(Fraction object) {
    if (object == null) {
        throw new NullPointerException("Object to compare cannot be null");
    }

    long thisNumerator = this.numerator;
    long thisDenominator = this.denominator;
    long otherNumerator = object.numerator;
    long otherDenominator = object.denominator;

    // Handle zero denominators
    if (thisDenominator == 0 && otherDenominator == 0) {
        return 0; // Both are undefined, consider them equal
    } else if (thisDenominator == 0) {
        return 1; // This fraction is undefined (infinity), considered greater
    } else if (otherDenominator == 0) {
        return -1; // Other fraction is undefined (infinity), considered smaller
    }

    // Calculate differences safely to avoid overflow
    long numeratorDifference = Math.multiplyExact(thisNumerator, otherDenominator) - Math.multiplyExact(otherNumerator, thisDenominator);

    return Long.signum(numeratorDifference);
}

public int compareTo(Fraction object) {
    if (object == null) {
        throw new NullPointerException("Object to compare cannot be null");
    }
    long n1 = this.numerator * (long) object.denominator;
    long n2 = object.numerator * (long) this.denominator;
    if (this.denominator == 0 || object.denominator == 0) {
        throw new ArithmeticException("Comparison not possible with zero denominator");
    }
    return Long.compare(n1, n2);
}

